const fs = require('fs');

function parseLine(line, delim) {
  let fields = [];
  let field = '';
  let inQuote = false;
  let i = 0;
  while (i < line.length) {
    let char = line[i];
    if (inQuote) {
      if (char === '"') {
        if (i + 1 < line.length && line[i + 1] === '"') {
          field += '"';
          i++;
        } else {
          inQuote = false;
        }
      } else {
        field += char;
      }
    } else {
      if (char === delim) {
        fields.push(field);
        field = '';
      } else if (char === '"') {
        inQuote = true;
      } else {
        field += char;
      }
    }
    i++;
  }
  fields.push(field);
  return fields;
}

const input = fs.readFileSync(0, 'utf-8').trim();
const lines = input.split(/\r?\n/);
if (lines.length === 0 || (lines.length === 1 && lines[0] === '')) {
