const possibleDelims = [',', ';', '\t'];
let selectedDelim = null;
let selectedFieldCount = 0;

for (let delim of possibleDelims) {
  let checkLines = lines.slice(0, Math.min(5, lines.length));
  let counts = checkLines.map(line => parseLine(line, delim).length);
  let firstCount = counts[0];
  if (firstCount <= 1) continue;
  let consistent = counts.every(c => c === firstCount);
  if (consistent && firstCount > selectedFieldCount) {
    selectedDelim = delim;
    selectedFieldCount = firstCount;
  }
}

if (selectedDelim === null) {
